+// Pipe clauses are contextual: AGGREGATE and EXTEND are identifiers in normal SQL,
+// while FROM and GROUP BY retain their normal meaning outside a pipe query.
+function detectPipeSyntax(tokens: Token[]): Token[] {
+  const pipeIndexes = tokens
+    .map((token, index) => (token.type === TokenType.PIPE_OPERATOR ? index : -1))
+    .filter(index => index !== -1);
+  const pipeFromIndexes = new Set<number>();
+
+  pipeIndexes.forEach(pipeIndex => {
+    const pipeDepth = parenthesisDepth(tokens, pipeIndex);
+    for (let i = pipeIndex - 1; i >= 0; i--) {
+      const token = tokens[i];
+      const depth = parenthesisDepth(tokens, i);
+      if (depth < pipeDepth || (depth === pipeDepth && token.type === TokenType.DELIMITER)) {
+        break;
+      }
+      if (depth === pipeDepth && token.text === 'FROM' && token.type === TokenType.RESERVED_CLAUSE) {
+        pipeFromIndexes.add(i);
+        break;
+      }
+    }
+  });
+
+  return tokens.map((token, index) => {
+    if (pipeFromIndexes.has(index)) {
+      return { ...token, type: TokenType.PIPE_FROM };
+    }
+
+    const previousPipe = previousPipeIndex(tokens, index);
+    if (previousPipe !== undefined && nextNonCommentIndex(tokens, previousPipe) === index) {
+      if (pipeClauseKeywords.has(token.text)) {
+        return { ...token, type: TokenType.PIPE_CLAUSE };
+      }
+    }
+
+    if (
+      token.text === 'GROUP BY' &&
+      token.type === TokenType.RESERVED_CLAUSE &&
+      isAggregateGroupBy(tokens, index)
+    ) {
+      return { ...token, type: TokenType.PIPE_GROUP_BY };
+    }
+    return token;
+  });
+}
