+function parenthesisDepth(tokens: Token[], end: number): number {
+  let depth = 0;
+  for (let i = 0; i < end; i++) {
+    if (tokens[i].type === TokenType.OPEN_PAREN) depth++;
+    if (tokens[i].type === TokenType.CLOSE_PAREN) depth--;
+  }
+  return depth;
+}
+
+function nextNonCommentIndex(tokens: Token[], index: number): number | undefined {
+  for (let i = index + 1; i < tokens.length; i++) {
+    if (tokens[i].type !== TokenType.BLOCK_COMMENT && tokens[i].type !== TokenType.LINE_COMMENT) {
+      return i;
+    }
+  }
+  return undefined;
+}
+
+function previousPipeIndex(tokens: Token[], index: number): number | undefined {
+  const depth = parenthesisDepth(tokens, index);
+  for (let i = index - 1; i >= 0; i--) {
+    if (parenthesisDepth(tokens, i) < depth) break;
+    if (parenthesisDepth(tokens, i) === depth && tokens[i].type === TokenType.PIPE_OPERATOR) return i;
+  }
+  return undefined;
+}
+
+function isAggregateGroupBy(tokens: Token[], index: number): boolean {
+  const pipeIndex = previousPipeIndex(tokens, index);
+  if (pipeIndex === undefined) return false;
+  const clauseIndex = nextNonCommentIndex(tokens, pipeIndex);
+  return clauseIndex !== undefined && tokens[clauseIndex].text === 'AGGREGATE';
